/**
 * Overlay wrapper ‚Äî animated pink/green laser scanner taper.
 *
 *   ‚îÄ‚îÄ‚îÄ‚îÄ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê[ Title ]‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÄ‚îÄ‚îÄ‚îÄ
 *   Pink spotlight sweeps from center leftward and rightward
 *   in sync ‚Äî classic KITT scanner on the taper line.
 *
 *   Dark grey bg, white text, 2-col margin.
 */

import type { Theme } from "@earendil-works/pi-coding-agent";
import { Container, visibleWidth } from "@earendil-works/pi-tui";

/** Theme fg/bg methods ‚Äî picks the exact overloads from pi's Theme class. */
export type ThemeProxy = Pick<Theme, "fg" | "bg">;

const PANEL_BG = "\x1b[48;5;232m";
const RESET_WHITE = "\x1b[0m\x1b[38;5;255m";

function wrapPanel(text: string): string {
	return PANEL_BG + text + RESET_WHITE;
}

const TAPER_CHARS = ["‚îÄ", "‚îÅ", "‚ïê"];

function taperChars(width: number): string[] {
	const chars: string[] = [];
	for (let i = 0; i < width; i++) {
		const ct = (width - 1) / 2;
		const dist = Math.abs(i - ct) / Math.max(1, ct);
		const idx = Math.round((1 - dist) * (TAPER_CHARS.length - 1));
		chars.push(TAPER_CHARS[Math.max(0, Math.min(idx, TAPER_CHARS.length - 1))]);
	}
	return chars;
}

const GREEN_BRIGHT = "\x1b[38;5;119m";
const GREEN_MID = "\x1b[38;5;108m";
const GREEN_DIM = "\x1b[38;5;65m";
const RESET = "\x1b[0m";

/** Build a mirrored green taper with two spots sweeping center‚Üíout‚Üícenter.
 *  All green ‚Äî bright spots at the moving edges, dim in the middle. */
export function scannerTaper(
	width: number,
	scanSpread: number,
	t: ThemeProxy,
	title?: string,
): string {
	if (width <= 0) return "";
	const chars = taperChars(width);
	const ct = (width - 1) / 2;
	// scanSpread 0 = center, 1 = edges
	const leftScan = Math.round(ct - scanSpread * ct);
	const rightScan = Math.round(ct + scanSpread * ct);

	const colorLine = (lineChars: string[], offset: number): string => {
		return lineChars
			.map((ch, i) => {
				const absIdx = offset + i;
				const minDist = Math.min(
					Math.abs(absIdx - leftScan),
					Math.abs(absIdx - rightScan),
				);
				if (minDist <= 5) {
					const c =
						minDist <= 1 ? GREEN_BRIGHT : minDist <= 3 ? GREEN_MID : GREEN_DIM;
					return `${c}${ch}${RESET}`;
				}
				return `${GREEN_DIM}${ch}${RESET}`;
			})
			.join("");
	};

	if (title) {
		const titleStr = `[ ${t.fg("text", title)} ]`;
		const tv = visibleWidth(titleStr);
		const lw = Math.floor((width - tv) / 2);
		const rw = width - tv - lw;
		const left = colorLine(chars.slice(0, lw), 0);
		const right = colorLine(chars.slice(lw + tv, lw + tv + rw), lw + tv);
		return left + titleStr + right;
	}

	return colorLine(chars, 0);
}

export function taperTitle(
	title: string,
	width: number,
	fg: (v: string, t: string) => string,
): string {
	const titleStr = `‚ïê[ ${fg("text", title)} ]`;
	const tv = visibleWidth(titleStr);
	const lw = Math.floor((width - tv) / 2);
	const rw = width - tv - lw;
	return fg(
		"accent",
		taperChars(lw).join("") + titleStr + taperChars(rw).join(""),
	);
}

export class Overlay {
	private theme: ThemeProxy;
	private title: string;
	private body: Container;
	private footerLines: string[];
	private animStart: number;
	private maxHeight: number;

	constructor(
		theme: ThemeProxy,
		opts: { title?: string; maxHeight?: number } = {},
	) {
		this.theme = theme;
		this.title = opts.title ?? "";
		this.body = new Container();
		this.footerLines = [];
		this.animStart = Date.now();
		this.maxHeight = opts.maxHeight ?? 0;
	}

	addBody(component: {
		render: (w: number) => string[];
		invalidate: () => void;
	}): void {
		this.body.addChild(component);
	}

	addFooter(line: string): void {
		this.footerLines.push(line);
	}

	dispose(): void {
		// No individual timer to clean ‚Äî scan position is time-computed in render()
	}

	render(fullW: number): string[] {
		const margin = 2;
		const innerW = Math.max(20, fullW - margin * 2);
		const t = this.theme;
		const dim = (s: string) => t.fg("dim", s);

		// ‚îÄ‚îÄ Scanner position: time-based ping-pong (0‚Üí1‚Üí0), no timer needed ‚îÄ‚îÄ
		const elapsed = (Date.now() - this.animStart) / 1000;
		const cycle = 0.66;
		const phase = (elapsed % (cycle * 2)) / cycle;
		const scanPos = phase <= 1 ? phase : 2 - phase;

		const indent = 4;
		const topRule = scannerTaper(innerW, scanPos, t, this.title);
		const bottomRule = scannerTaper(innerW, scanPos, t);

		// Reserve space for frame elements so footer + bottom rule never get clipped
		const footerCount = this.footerLines.length;
		const overhead = 3 + (footerCount > 0 ? footerCount + 2 : 0); // top rule + empty line + bottom rule (+ footer lines + empty lines)
		const bodyMax =
			this.maxHeight > 0 ? Math.max(0, this.maxHeight - overhead) : Infinity;

		let bodyLines = this.body.render(innerW - indent);
		if (bodyLines.length > bodyMax) {
			bodyLines = bodyLines.slice(0, bodyMax);
		}

		const result: string[] = [];
		result.push(topRule);
		result.push("");
		for (const line of bodyLines) {
			result.push(" ".repeat(indent) + line);
		}
		if (footerCount > 0) result.push("");
		for (const f of this.footerLines) {
			result.push(" ".repeat(indent) + dim(f));
		}
		if (footerCount > 0) result.push("");
		result.push(bottomRule);

		// ‚îÄ‚îÄ Pad with dark grey bg + margin ‚îÄ‚îÄ
		const leftPad = " ".repeat(margin);
		return result.map((line) => {
			const vis = visibleWidth(line);
			const rightPad = " ".repeat(Math.max(0, fullW - margin - vis - margin));
			return wrapPanel(leftPad + line + rightPad);
		});
	}

	invalidate(): void {
		this.body.invalidate();
	}
}

