						cursor: theme.fg("accent", "‚ñ∏"),
						hint: (s) => theme.fg("dim", s),
					};
					const settingsList = new SettingsList(
						items,
						8,
						settingsTheme,
						(id, newValue) => {
							const updated = loadConfig();
							(updated as any)[id] = newValue;
							saveConfig(updated);
							bakeCtx.requestWidgetRender?.();
							const desc =
								newValue === "full"
									? "List all phases (tall ‚Äî needs vertical space)"
									: newValue === "compact"
										? "Single-line summary (phone-friendly)"
										: "Widget hidden entirely";
							items[0].description = desc;
							items[0].currentValue = newValue;
						},
						() => done(undefined),
						{ enableSearch: false },
					);
					ov.addBody(settingsList);
					ov.addFooter("‚Üë‚Üì navigate  ¬∑  ‚Üê ‚Üí / space change  ¬∑  esc close");

					return {
						render: (w) => ov.render(w),
						invalidate: () => ov.invalidate(),
						handleInput: (data) => settingsList.handleInput?.(data),
						dispose: () => ov.dispose(),
					};
				},
				{ overlay: true },
			);
			} finally {
				bakeCtx.widgetHidden = false;
				bakeCtx.requestWidgetRender?.();
			}
		},
	});
}

